import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { getApiUrl } from '../config/apiConfig';
import './VehicleStandalone.css';

const VehicleStandalone = () => {
  const site = window.location.pathname.startsWith('/lon') ? 'longuenesse' : 'arras';
  const siteLabel = site === 'longuenesse' ? 'Longuenesse' : 'Arras';
  const apiBase = getApiUrl();

  const [drivers, setDrivers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [msg, setMsg] = useState('');
  const [msgOk, setMsgOk] = useState(true);

  const [driverId, setDriverId] = useState('');
  const [kmDepart, setKmDepart] = useState('');
  const [ei, setEi] = useState(3);
  const [ee, setEe] = useState(3);
  const [remDep, setRemDep] = useState('');

  const [activeTrip, setActiveTrip] = useState(null);

  const [destinationLabels, setDestinationLabels] = useState([]);
  const [destModalOpen, setDestModalOpen] = useState(false);
  const [selectedDestinations, setSelectedDestinations] = useState([]);
  /** Lieu absent de la liste paramétrée (complément aux cases cochées) */
  const [nouvelleDestination, setNouvelleDestination] = useState('');
  const [destination, setDestination] = useState('');
  const [kmRetour, setKmRetour] = useState('');
  const [pv, setPv] = useState(false);
  const [pa, setPa] = useState(false);
  const [probRem, setProbRem] = useState('');
  const [tdLav, setTdLav] = useState(false);
  const [tdPneu, setTdPneu] = useState(false);
  const [tdRev, setTdRev] = useState(false);
  const [tdPl, setTdPl] = useState(false);
  const [pleinEffectue, setPleinEffectue] = useState(false);
  const [pleinParId, setPleinParId] = useState('');
  const [photoRetourFile, setPhotoRetourFile] = useState(null);

  useEffect(() => {
    (async () => {
      setLoading(true);
      setMsg('');
      try {
        const [dr, cfg] = await Promise.all([
          axios.get(`${apiBase}/vehicle/drivers`, { params: { site } }),
          axios.get(`${apiBase}/vehicle/config`, { params: { site } })
        ]);
        setDrivers(dr.data?.data || []);
        setDestinationLabels(
          Array.isArray(cfg.data?.data?.destinationLabels) ? cfg.data.data.destinationLabels : []
        );
        setDriverId('');
        setPleinParId('');
      } catch (e) {
        setMsg(e.response?.data?.error || 'Erreur chargement conducteurs');
        setMsgOk(false);
      } finally {
        setLoading(false);
      }
    })();
  }, [apiBase, site]);

  const startTrip = async (e) => {
    e.preventDefault();
    if (!driverId || kmDepart === '') {
      setMsg('Conducteur et km départ requis');
      setMsgOk(false);
      return;
    }
    setLoading(true);
    setMsg('');
    try {
      const r = await axios.post(`${apiBase}/vehicle/trips`, {
        site,
        driverId,
        kmDepart: Number(String(kmDepart).replace(',', '.')),
        etatInterieur: ei,
        etatExterieur: ee,
        remarquesDepart: remDep
      });
      const trip = r.data?.data;
      setActiveTrip(trip);
      setKmRetour('');
      setDestination('');
      setNouvelleDestination('');
      setSelectedDestinations([]);
      setPv(false);
      setPa(false);
      setProbRem('');
      setTdLav(false);
      setTdPneu(false);
      setTdRev(false);
      setTdPl(false);
      setPleinEffectue(false);
      setPleinParId(driverId);
      setPhotoRetourFile(null);
      setMsg('Départ enregistré — complétez le retour ci-dessous.');
      setMsgOk(true);
    } catch (err) {
      setMsg(err.response?.data?.error || 'Erreur');
      setMsgOk(false);
    } finally {
      setLoading(false);
    }
  };

  const resumeLastTrip = async () => {
    if (!driverId) {
      setMsg('Choisissez un conducteur pour reprendre une saisie');
      setMsgOk(false);
      return;
    }
    if (activeTrip?._id) return;
    setLoading(true);
    setMsg('');
    try {
      const r = await axios.get(`${apiBase}/vehicle/trips/last-open`, { params: { site, driverId } });
      const trip = r.data?.data || null;
      if (!trip?._id) {
        setMsg('Aucune saisie départ en cours trouvée pour ce conducteur.');
        setMsgOk(false);
        return;
      }
      setActiveTrip(trip);
      setKmDepart(trip.kmDepart != null ? String(trip.kmDepart) : '');
      setEi(trip.etatInterieur != null ? Number(trip.etatInterieur) : 3);
      setEe(trip.etatExterieur != null ? Number(trip.etatExterieur) : 3);
      setRemDep(trip.remarquesDepart || '');
      setKmRetour('');
      setDestination('');
      setNouvelleDestination('');
      setSelectedDestinations([]);
      setPv(false);
      setPa(false);
      setProbRem('');
      setTdLav(false);
      setTdPneu(false);
      setTdRev(false);
      setTdPl(false);
      setPleinEffectue(false);
      setPleinParId(driverId);
      setPhotoRetourFile(null);
      setMsg('Dernière saisie reprise — complétez le retour ci-dessous.');
      setMsgOk(true);
    } catch (err) {
      setMsg(err.response?.data?.error || 'Erreur reprise saisie');
      setMsgOk(false);
    } finally {
      setLoading(false);
    }
  };

  const completeReturn = async (e) => {
    e.preventDefault();
    if (!activeTrip?._id) return;
    const hasList = destinationLabels.length > 0;
    const extraDest = nouvelleDestination.trim();
    if (hasList && selectedDestinations.length === 0 && !extraDest) {
      setMsg('Choisissez au moins une destination dans la liste ou saisissez une nouvelle destination');
      setMsgOk(false);
      return;
    }
    if (!hasList && !destination.trim()) {
      setMsg('Indiquez la destination');
      setMsgOk(false);
      return;
    }
    const kr = Number(String(kmRetour).replace(',', '.'));
    if (Number.isNaN(kr)) {
      setMsg('Km retour invalide');
      setMsgOk(false);
      return;
    }
    setLoading(true);
    setMsg('');
    try {
      const body = {
        site,
        kmRetour: kr,
        problemeVoyantMoteur: pv,
        problemeAutre: pa,
        problemeRemarque: probRem,
        todoLaveGlace: tdLav,
        todoPneu: tdPneu,
        todoRevision: tdRev,
        todoPlein: tdPl,
        pleinEffectue,
        pleinParEmployeeId: pleinEffectue ? (pleinParId || driverId) : undefined
      };
      if (destinationLabels.length > 0) {
        const parts = [...selectedDestinations];
        if (extraDest) {
          const seen = new Set(parts.map((p) => p.toLowerCase()));
          if (!seen.has(extraDest.toLowerCase())) parts.push(extraDest);
        }
        body.destinations = parts;
      } else {
        body.destination = destination.trim();
      }
      const r = await axios.put(`${apiBase}/vehicle/trips/${activeTrip._id}/return`, body);
      const trip = r.data?.data;

      if (photoRetourFile && trip?._id) {
        try {
          const fd = new FormData();
          fd.append('file', photoRetourFile);
          await axios.post(`${apiBase}/vehicle/trips/${trip._id}/photo-retour`, fd, {
            params: { site },
            timeout: 120000
          });
        } catch (upErr) {
          setMsg(
            `Trajet enregistré, mais échec envoi photo : ${upErr.response?.data?.error || upErr.message}`
          );
          setMsgOk(false);
          setActiveTrip(null);
          setKmDepart('');
          setRemDep('');
          setNouvelleDestination('');
          setSelectedDestinations([]);
          setPhotoRetourFile(null);
          setLoading(false);
          return;
        }
      }

      setMsg('Trajet terminé. Merci !');
      setMsgOk(true);
      setActiveTrip(null);
      setKmDepart('');
      setRemDep('');
      setNouvelleDestination('');
      setSelectedDestinations([]);
      setPhotoRetourFile(null);
    } catch (err) {
      setMsg(err.response?.data?.error || 'Erreur');
      setMsgOk(false);
    } finally {
      setLoading(false);
    }
  };

  const toggleDestination = (name) => {
    setSelectedDestinations((prev) => {
      const i = prev.indexOf(name);
      if (i >= 0) return prev.filter((_, j) => j !== i);
      return [...prev, name];
    });
  };

  const Rating = ({ value, onChange, label }) => (
    <div className="vs-field">
      <label>{label} (1 = mauvais, 5 = bon)</label>
      <div className="vs-rating">
        {[1, 2, 3, 4, 5].map((n) => (
          <button
            key={n}
            type="button"
            className={value === n ? 'active' : ''}
            onClick={() => onChange(n)}
          >
            {n}
          </button>
        ))}
      </div>
    </div>
  );

  return (
    <div className="vs-page">
      <h1>🚗 Véhicule</h1>
      <p style={{ color: '#555', fontSize: '0.95rem' }}>
        Enregistrement départ / retour (usage interne) — <strong>{siteLabel}</strong>
      </p>

      {msg && (
        <div className={`vs-msg ${msgOk ? 'ok' : 'err'}`}>{msg}</div>
      )}

      {!loading && drivers.length === 0 && (
        <div className="vs-msg err">
          Aucun conducteur autorisé. Dans <strong>Gestion des employés</strong>, cochez « Autoriser à conduire le véhicule »
          sous le téléphone d’urgence.
        </div>
      )}

      {loading && !drivers.length ? (
        <p>Chargement…</p>
      ) : (
        <>
          <div className="vs-card">
            <h2>Départ</h2>
            <form onSubmit={startTrip}>
              <div className="vs-field">
                <label>Conducteur</label>
                <select value={driverId} onChange={(e) => setDriverId(e.target.value)} required>
                  <option value="">— Choisir —</option>
                  {drivers.map((d) => (
                    <option key={d._id} value={d._id}>
                      {d.name}
                    </option>
                  ))}
                </select>
              </div>
              <div className="vs-field">
                <label>Km départ (compteur)</label>
                <input
                  type="text"
                  inputMode="decimal"
                  value={kmDepart}
                  onChange={(e) => setKmDepart(e.target.value)}
                  required
                />
              </div>
              <Rating label="État intérieur" value={ei} onChange={setEi} />
              <Rating label="État extérieur" value={ee} onChange={setEe} />
              <div className="vs-field">
                <label>Remarques (optionnel)</label>
                <textarea rows={2} value={remDep} onChange={(e) => setRemDep(e.target.value)} />
              </div>
              <div className="vs-btn-row">
                <button type="submit" className="vs-btn vs-btn-primary" disabled={loading || !!activeTrip}>
                  {activeTrip ? 'Départ déjà enregistré' : 'Enregistrer le départ'}
                </button>
                <button
                  type="button"
                  className="vs-btn vs-btn-secondary"
                  disabled={loading || !!activeTrip || !driverId}
                  onClick={resumeLastTrip}
                  title={!driverId ? 'Choisissez un conducteur' : 'Reprendre la dernière saisie incomplète'}
                >
                  Reprendre la dernière saisie
                </button>
              </div>
            </form>
          </div>

          {activeTrip && (
            <div className="vs-card">
              <h2>Retour</h2>
              <form onSubmit={completeReturn}>
                <div className="vs-field">
                  <label>Destination</label>
                  {destinationLabels.length > 0 ? (
                    <>
                      <button
                        type="button"
                        className="vs-dest-trigger"
                        onClick={() => setDestModalOpen(true)}
                      >
                        {selectedDestinations.length
                          ? selectedDestinations.join(' · ')
                          : 'Toucher pour choisir…'}
                      </button>
                      <p className="vs-dest-hint">
                        {selectedDestinations.length > 0
                          ? `${selectedDestinations.length} lieu(x) — ordre = ordre de sélection`
                          : 'Plusieurs choix possibles pour une tournée'}
                      </p>
                      <div className="vs-field vs-field-nested">
                        <label htmlFor="vs-nouvelle-dest">Nouvelle destination (si absente de la liste)</label>
                        <input
                          id="vs-nouvelle-dest"
                          type="text"
                          autoComplete="off"
                          value={nouvelleDestination}
                          onChange={(e) => setNouvelleDestination(e.target.value)}
                          placeholder="Ex. client ponctuel, adresse…"
                        />
                      </div>
                    </>
                  ) : (
                    <input
                      value={destination}
                      onChange={(e) => setDestination(e.target.value)}
                      placeholder="Saisie libre (aucune liste configurée côté gestion)"
                      required
                    />
                  )}
                </div>

                {destModalOpen && destinationLabels.length > 0 && (
                  <div
                    className="vs-modal-overlay"
                    role="presentation"
                    onClick={() => setDestModalOpen(false)}
                  >
                    <div
                      className="vs-modal"
                      role="dialog"
                      aria-label="Choisir les destinations"
                      onClick={(e) => e.stopPropagation()}
                    >
                      <h3 className="vs-modal-title">Destinations</h3>
                      <p className="vs-modal-hint">
                        Cochez les lieux visités pendant la tournée (plusieurs possibles).
                      </p>
                      <div className="vs-dest-list">
                        {destinationLabels.map((name) => (
                          <label
                            key={name}
                            className={`vs-dest-item ${selectedDestinations.includes(name) ? 'on' : ''}`}
                          >
                            <input
                              type="checkbox"
                              checked={selectedDestinations.includes(name)}
                              onChange={() => toggleDestination(name)}
                            />
                            <span>{name}</span>
                          </label>
                        ))}
                      </div>
                      <button
                        type="button"
                        className="vs-btn vs-btn-primary"
                        onClick={() => setDestModalOpen(false)}
                      >
                        Valider
                      </button>
                    </div>
                  </div>
                )}
                <div className="vs-field">
                  <label>Km retour (compteur)</label>
                  <input
                    type="text"
                    inputMode="decimal"
                    value={kmRetour}
                    onChange={(e) => setKmRetour(e.target.value)}
                    required
                  />
                </div>

                <p style={{ fontWeight: 600, margin: '0.75rem 0 0.35rem' }}>Problème</p>
                <div className="vs-toggle-row">
                  <button
                    type="button"
                    className={`vs-toggle ${pv ? 'on' : ''}`}
                    onClick={() => setPv(!pv)}
                  >
                    Voyant moteur
                  </button>
                  <button
                    type="button"
                    className={`vs-toggle ${pa ? 'on' : ''}`}
                    onClick={() => setPa(!pa)}
                  >
                    Autre
                  </button>
                </div>
                <div className="vs-field">
                  <label>Remarque problème</label>
                  <textarea rows={2} value={probRem} onChange={(e) => setProbRem(e.target.value)} />
                </div>

                <p style={{ fontWeight: 600, margin: '0.75rem 0 0.35rem' }}>À faire</p>
                <div className="vs-toggle-row">
                  <button type="button" className={`vs-toggle ${tdLav ? 'on' : ''}`} onClick={() => setTdLav(!tdLav)}>
                    Lave-glace
                  </button>
                  <button type="button" className={`vs-toggle ${tdPneu ? 'on' : ''}`} onClick={() => setTdPneu(!tdPneu)}>
                    Pneu
                  </button>
                  <button type="button" className={`vs-toggle ${tdRev ? 'on' : ''}`} onClick={() => setTdRev(!tdRev)}>
                    Révision
                  </button>
                  <button type="button" className={`vs-toggle ${tdPl ? 'on' : ''}`} onClick={() => setTdPl(!tdPl)}>
                    Plein (à faire)
                  </button>
                </div>

                <p style={{ fontWeight: 600, margin: '0.75rem 0 0.35rem' }}>Plein effectué</p>
                <div className="vs-field">
                  <label>
                    <input
                      type="checkbox"
                      checked={pleinEffectue}
                      onChange={(e) => {
                        setPleinEffectue(e.target.checked);
                        if (e.target.checked && !pleinParId) setPleinParId(driverId);
                      }}
                    />{' '}
                    Plein effectué maintenant (enregistre la date et le km retour)
                  </label>
                </div>
                {pleinEffectue && (
                  <div className="vs-field">
                    <label>Enregistré par</label>
                    <select value={pleinParId} onChange={(e) => setPleinParId(e.target.value)}>
                      {drivers.map((d) => (
                        <option key={d._id} value={d._id}>
                          {d.name}
                        </option>
                      ))}
                    </select>
                  </div>
                )}

                <div className="vs-field">
                  <label>Photo du retour (optionnel)</label>
                  <input
                    type="file"
                    accept="image/jpeg,image/png,image/gif,image/webp,.heic"
                    onChange={(e) => setPhotoRetourFile(e.target.files?.[0] || null)}
                  />
                  <p className="vs-photo-hint">Stockée sur le NAS (dossier véhicule du site).</p>
                </div>

                <button type="submit" className="vs-btn vs-btn-primary" disabled={loading}>
                  Terminer le trajet
                </button>
              </form>
            </div>
          )}
        </>
      )}
    </div>
  );
};

export default VehicleStandalone;
